package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.Charset;
import java.nio.file.Path;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrint() throws IOException {
        // Arrange
        Path path = Path.of("test.csv");
        Charset charset = Charset.defaultCharset();
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVPrinter csvPrinterMock = mock(CSVPrinter.class);

        CSVFormat csvFormatSpy = spy(csvFormat);
        doReturn(csvPrinterMock).when(csvFormatSpy).print(any(File.class), any(Charset.class));

        // Act
        CSVPrinter result = csvFormatSpy.print(path, charset);

        // Assert
        assertEquals(csvPrinterMock, result);
        verify(csvFormatSpy).print(any(File.class), any(Charset.class));
    }
}
